solution_code:
#include <stdio.h>
#include <stdlib.h>

int alloc_sequence(int **out, int n) {
    *out = malloc(n * sizeof(int));
    if (!*out) return -1;
    for (int i = 0; i < n; i++) {
        (*out)[i] = i * i;
    }
    return 0;
}

int main(void) {
    int *data = NULL;
    int n = 6;
    if (alloc_sequence(&data, n) != 0) {
        fprintf(stderr, "Erreur allocation\n");
        return 1;
    }
    for (int i = 0; i < n; i++) printf("%d ", data[i]);
    printf("\n");
    free(data);
    return 0;
}

